function smallestSubsequence(s, k, letter, repetition) {
    let n = s.length;
    let remaining = n - k;
    let letterCount = 0;

    let res = [];
    for (const c of s) {
        while (res.length && res[res.length - 1] > c && remaining > 0) {
            if (res[res.length - 1] === letter) {
                if (letterCount > repetition) {
                    --letterCount;
                    res.pop();
                    --remaining;
                }
            } else {
                res.pop();
                --remaining;
            }
        }
        if (res.length < k) {
            if (c === letter) {
                ++letterCount;
            } else if (k - res.length > repetition - letterCount) {
            } else {
                continue;
            }
            res.push(c);
        }
    }

    return res.join('');
}
