import java.util.*;

public String smallestSubsequence(String s, int k, char letter, int repetition) {
    int n = s.length();
    int remaining = n - k;
    int letterCount = 0;

    ArrayDeque<Character> resQueue = new ArrayDeque<>();
    for (char c : s.toCharArray()) {
        while (!resQueue.isEmpty() && resQueue.peekLast() > c && remaining > 0) {
            if (resQueue.peekLast() == letter) {
                if (letterCount > repetition) {
                    --letterCount;
                    resQueue.pollLast();
                    --remaining;
                }
            } else {
                resQueue.pollLast();
                --remaining;
            }
        }
        if (resQueue.size() < k) {
            if (c == letter) {
                ++letterCount;
            } else if (k - resQueue.size() > repetition - letterCount) {
            } else {
                continue;
            }
            resQueue.offerLast(c);
        }
    }

    StringBuilder sb = new StringBuilder();
    while (!resQueue.isEmpty()) {
        sb.append(resQueue.pollFirst());
    }
    return sb.toString();
}
